package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class GsonBuilderTest {

  @Test
  void testEnableComplexMapKeySerialization() throws Exception {
    GsonBuilder builder = new GsonBuilder();

    // Initially complexMapKeySerialization should be false (default)
    Field complexMapKeyField = GsonBuilder.class.getDeclaredField("complexMapKeySerialization");
    complexMapKeyField.setAccessible(true);
    boolean initialValue = complexMapKeyField.getBoolean(builder);
    assertFalse(initialValue, "complexMapKeySerialization should be false by default");

    // Call enableComplexMapKeySerialization
    GsonBuilder returnedBuilder = builder.enableComplexMapKeySerialization();

    // The method should return the same builder instance
    assertSame(builder, returnedBuilder, "enableComplexMapKeySerialization should return the same builder instance");

    // The complexMapKeySerialization field should now be true
    boolean updatedValue = complexMapKeyField.getBoolean(builder);
    assertTrue(updatedValue, "complexMapKeySerialization should be true after calling enableComplexMapKeySerialization");
  }
}
